@app.before_request
def log_request_info():
    """Logs detailed information about incoming API requests."""
    g.start_time = datetime.now() # Store request start time to calculate duration
    
    # Generate a request ID if not provided by a proxy, useful for tracing
    g.request_id = request.headers.get('X-Request-ID', f"req-{datetime.now().timestamp()}-{request.remote_addr.replace('.', '')}")
    
    # Extract user information if available (e.g., from an authentication token after parsing)
    # For this example, we'll use a header or a placeholder.
    user_id = request.headers.get('X-User-ID', 'Anonymous') 
    
    log_data = {
        "request_id": g.request_id,
        "method": request.method,
        "path": request.path,
        "query_string": request.query_string.decode('utf-8') if request.query_string else "",
        "remote_addr": request.remote_addr,
        "user_agent": request.headers.get('User-Agent'),
        "user_id": user_id,
        "headers": dict(request.headers),
        "body": None
    }

    # Log request body if present, and mask sensitive fields
    try:
        if request.is_json:
            json_data = request.get_json(silent=True)
            if json_data:
                log_data["body"] = mask_sensitive_data(json_data)
        elif request.form:
            form_data = dict(request.form)
            if form_data:
                log_data["body"] = mask_sensitive_data(form_data)
        elif request.data:
            # For non-JSON/form bodies, log a truncated version or its type
            log_data["body"] = f"Raw body (type: {request.content_type}, length: {len(request.data)} bytes)"
    except Exception as e:
        logger.error(f"[{g.request_id}] Error parsing request body: {e}", exc_info=True)
        log_data["body_parse_error"] = str(e)
    
    logger.info(f"[{g.request_id}] Incoming Request: {json.dumps(log_data)}")

@app.after_request
def log_response_info(response):
    """Logs detailed information about outgoing API responses."""
    elapsed_time = (datetime.now() - g.start_time).total_seconds() if hasattr(g, 'start_time') else 'N/A'
    
    # Log response body for debugging, but be cautious with large bodies
    # or highly sensitive data in responses. For this example, we'll log it,
    # but in production, you might want to truncate or exclude for certain endpoints.
    response_body = None
    try:
        if response.is_json:
            # Attempt to parse and log JSON response.
            # response.get_json() is not available here, so we get data directly.
            # Note: response.data is bytes, must decode.
            if response.data:
                parsed_json = json.loads(response.data.decode('utf-8'))
                response_body = mask_sensitive_data(parsed_json)
        elif 'text/html' in response.headers.get('Content-Type', ''):
            # For HTML, we might log a snippet or just its type/length
            response_body = f"HTML Response (length: {len(response.data)} bytes)"
        else:
            # Log other types as raw bytes or truncated
            response_body = response.data.decode('utf-8')[:500] + '...' if len(response.data) > 500 else response.data.decode('utf-8')
    except Exception as e:
        logger.warning(f"[{g.request_id}] Could not parse response body for logging: {e}")
        response_body = f"Raw data (could not parse): {response.data.decode('utf-8')[:500]}..." if response.data else "No data"

    log_data = {
        "request_id": g.request_id,
        "method": request.method,
        "path": request.path,
        "status_code": response.status_code,
        "elapsed_ms": round(float(elapsed_time) * 1000, 2),
        "headers": dict(response.headers),
        "response_body": response_body
    }
    
    logger.info(f"[{g.request_id}] Outgoing Response: {json.dumps(log_data)}")
    return response

@app.errorhandler(Exception)
def handle_exception(e):
    """Handles and logs all unhandled exceptions within the application."""
