@app.route('/login', methods=['POST'])
def login():
    if not request.is_json:
        logger.warning(f"[{g.request_id}] Login attempt with non-JSON content type.")
        return jsonify(message="Content-Type must be application/json"), 400

    data = request.get_json(silent=True)
    if not data:
        logger.warning(f"[{g.request_id}] Login attempt with empty or malformed JSON body.")
        return jsonify(message="Invalid JSON body."), 400

    username = data.get('username')
    password = data.get('password') # The password itself is masked in logs by `before_request`

    # Simulate authentication logic
